parameters.text:
=You are a senior software engineer doing sprint planning.

Estimate the following GitHub issue using Fibonacci story points: 1, 2, 3, 5, 8, or 13. Consider complexity, unknowns, and scope.

Issue #{{ $json.number }}: {{ $json.title }}
Labels: {{ $json.labels.map(l => l.name).join(', ') || 'none' }}
Body: {{ ($json.body || 'No description').substring(0, 500) }}

Respond ONLY with a valid JSON object — no markdown, no extra text:
{"number": {{ $json.number }}, "title": "{{ $json.title.replace(/"/g, "'") }}", "labels": {{ JSON.stringify($json.labels.map(l => l.name)) }}, "estimate": 3, "rationale": "one sentence"}

parameters.jsCode:
// This node receives all items from the loop's 'done' output.
// Each item has $json.output from the AI agent (one per issue).
const items = $input.all();
const estimates = [];

for (const item of items) {
  const raw = item.json.output || '';
  try {
    const cleaned = raw.replace(/```json?\s*/gi, '').replace(/```/g, '').trim();
    const parsed = JSON.parse(cleaned);
    estimates.push({
      number: parsed.number,
      title: parsed.title,
      labels: parsed.labels || [],
      estimate: parsed.estimate,
      rationale: parsed.rationale
    });
  } catch (e) {
    estimates.push({
      number: item.json.number || null,
      title: item.json.title || 'Unknown',
      labels: [],
      estimate: null,
      rationale: 'Parse failed: ' + raw.substring(0, 80)
    });
  }
}

return [{ json: { estimates } }];

parameters.text:
=Parse the following sprint planning notes into a structured priority list.

Notes:
{{ $json.priorityNotes }}

Respond ONLY with valid JSON — no markdown, no extra text:
{"high": ["topic1"], "medium": ["topic2"], "low": ["topic3"]}

parameters.jsCode:
// GitHub file node → Extract from JSON gives $json.data.team
// Handles both: pre-parsed (via Extract from JSON) or raw base64 from GitHub API
const item = $input.first();

let teamSkills;
if (item.json.data && item.json.data.team) {
  teamSkills = item.json.data;
} else if (item.json.content) {
  const decoded = atob(item.json.content.replace(/\n/g, ''));
  teamSkills = JSON.parse(decoded);
} else {
  throw new Error('Team skills data not found. Expected $json.data.team or $json.content.');
}

return [{ json: { teamSkills } }];

// Combine the 3 appended items into one context object for the planner agent
const allItems = $input.all();

let estimates = [];
let priorities = { high: [], medium: [], low: [] };
let teamSkills = { team: [] };

for (const item of allItems) {
  if (item.json.estimates) {
    estimates = item.json.estimates;
  }
  if (item.json.teamSkills) {
    teamSkills = item.json.teamSkills;
  }
  // Priority agent output lands in item.json.output
  const raw = item.json.output || '';
  if (raw) {
    try {
      const cleaned = raw.replace(/```json?\s*/gi, '').replace(/```/g, '').trim();
      const parsed = JSON.parse(cleaned);
      if (parsed.high !== undefined) priorities = parsed;
    } catch (e) {}
  }
}

return [{ json: { estimates, priorities, teamSkills } }];

const item = $input.first();
const planMarkdown = item.json.output || 'No plan generated.';
const timestamp = new Date().toISOString().split('T')[0];
return [{ json: { sprintPlan: `# Sprint Plan — ${timestamp}\n\n${planMarkdown}`, generatedAt: timestamp } }];
